--- 装配徽章
---@param type number 状态：0--普通装配  1--一键装配
---@param refId number 徽章id
---@param position number 槽位
---@param heroId string 英雄id
function LxBadgeHandler:BadgeDressReq(type,refId,position,heroId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.BadgeDressReq)
    proto.type = type
    if refId and refId > 0 then
        proto.refId = refId
    end
    if position and position > 0 then
        proto.position = position
    end
    proto.heroId = heroId
    SendMessage(LxProtoIds.BadgeDressReq, proto)
end

--- 卸下徽章
---@param type number 状态：0--普通卸下  1--一键卸下
---@param refId number 徽章id
---@param heroId string 英雄id
function LxBadgeHandler:BadgeUndressReq(type,refId,heroId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.BadgeUndressReq)
    proto.type = type
    proto.refId = refId
    proto.heroId = heroId
    SendMessage(LxProtoIds.BadgeUndressReq, proto)
end

--- 徽章激活
---@param refId number 升星徽章id
function LxBadgeHandler:BadgeActiveReq(refId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.BadgeActiveReq)
    proto.refId = refId
    SendMessage(LxProtoIds.BadgeActiveReq, proto)
end

--- 徽章升星
---@param refId number 升星徽章id
function LxBadgeHandler:BadgeUpStarReq(refId,items)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.BadgeUpStarReq)
    proto.refId = refId
    local item = proto.item
    for i,v in ipairs(items) do
        ---@type LxIntKeyValue
        local pbItem = item:add()
        pbItem.key = v.key
        pbItem.value = v.value
    end
    SendMessage(LxProtoIds.BadgeUpStarReq, proto)
end

