--- 回收徽章
---@param badgeItems LxIntKeyValue[] 选择回收的道具，道具填充格式:<key=道具refId,value=数量>
function LxBadgeHandler:BadgeRecycleReq(badgeItems)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.BadgeRecycleReq)
    local pbbadgeItems = proto.badgeItems
    for i,v in ipairs(badgeItems) do
        ---@type LxIntKeyValue
        local pbbadgeItem = pbbadgeItems:add()
        pbbadgeItem.key = v.key
        pbbadgeItem.value = v.value
    end
    SendMessage(LxProtoIds.BadgeRecycleReq, proto)
end

