--- 装配徽章
function LxBadgeHandler:OnBadgeDressResp(pb)
    local dressLen = #pb.badges
    if dressLen > 0 then
        if pb.type == 1 then
            ShowSysMsg(I18nText(7847))
        else
            ShowSysMsg(I18nText(7851))
        end
    end
    ModuleCenter.Badge:SetBadges(pb.badges)
end

--- 卸下徽章
function LxBadgeHandler:OnBadgeUndressResp(pb)
    local dressLen = #pb.badges
    if dressLen > 0 then
        if pb.type == 1 then
            ShowSysMsg(I18nText(7848))
        else
            ShowSysMsg(I18nText(7849))
        end
    end
    ModuleCenter.Badge:SetBadges(pb.badges)
end

--- 徽章激活
function LxBadgeHandler:OnBadgeActiveResp(pb)
    ModuleCenter.Badge:SetBadge(pb.badge)
    FireEvent(EventNames.UPDATE_BADGE_DATA)
end

